INSERT INTO `question` (`title`, `content`, `tags`, `answer`, `difficulty`, `judgeCase`, `judgeConfig`, `userId`) VALUES
('课程表', '你这个学期必须选修 numCourses 门课程，记为 0 到 numCourses - 1 。\n\n在选修某些课程之前需要一些先修课程。 先修课程按数组 prerequisites 给出，其中 prerequisites[i] = [ai, bi] ，表示如果要学习课程 ai 则 必须 先学习课程 bi 。\n\n例如，先修课程对 [0, 1] 表示：想要学习课程 0 ，你需要先完成课程 1 。\n请你判断是否可能完成所有课程的学习？如果可以，返回 true ；否则，返回 false 。', '["图","拓扑排序"]', 'public boolean canFinish(int numCourses, int[][] prerequisites) {\n    int[] indegrees = new int[numCourses];\n    List<List<Integer>> adjacency = new ArrayList<>();\n    Queue<Integer> queue = new LinkedList<>();\n    for(int i = 0; i < numCourses; i++)\n        adjacency.add(new ArrayList<>());\n    for(int[] cp : prerequisites) {\n        indegrees[cp[0]]++;\n        adjacency.get(cp[1]).add(cp[0]);\n    }\n    for(int i = 0; i < numCourses; i++)\n        if(indegrees[i] == 0) queue.add(i);\n    while(!queue.isEmpty()) {\n        int pre = queue.poll();\n        numCourses--;\n        for(int cur : adjacency.get(pre))\n            if(--indegrees[cur] == 0) queue.add(cur);\n    }\n    return numCourses == 0;\n}', 'medium', '[{"input":"2,[[1,0]]","output":"true"},{"input":"2,[[1,0],[0,1]]","output":"false"}]', '{"timeLimit":1000,"memoryLimit":256,"stackLimit":256}', 1),

('编辑距离', '给你两个单词 word1 和 word2，请你计算出将 word1 转换成 word2 所使用的最少操作数。\n\n你可以对一个单词进行如下三种操作：\n1. 插入一个字符\n2. 删除一个字符\n3. 替换一个字符', '["字符串","动态规划"]', 'public int minDistance(String word1, String word2) {\n    int n = word1.length();\n    int m = word2.length();\n    int[][] dp = new int[n + 1][m + 1];\n    for (int i = 0; i <= n; i++) {\n        dp[i][0] = i;\n    }\n    for (int j = 0; j <= m; j++) {\n        dp[0][j] = j;\n    }\n    for (int i = 1; i <= n; i++) {\n        for (int j = 1; j <= m; j++) {\n            if (word1.charAt(i-1) == word2.charAt(j-1)) {\n                dp[i][j] = dp[i-1][j-1];\n            } else {\n                dp[i][j] = Math.min(Math.min(dp[i-1][j], dp[i][j-1]), dp[i-1][j-1]) + 1;\n            }\n        }\n    }\n    return dp[n][m];\n}', 'hard', '[{"input":"\"horse\",\"ros\"","output":"3"},{"input":"\"intention\",\"execution\"","output":"5"}]', '{"timeLimit":1000,"memoryLimit":256,"stackLimit":256}', 1),

('接雨水', '给定 n 个非负整数表示每个宽度为 1 的柱子的高度图，计算按此排列的柱子，下雨之后能接多少雨水。', '["栈","数组","双指针"]', 'public int trap(int[] height) {\n    int left = 0, right = height.length - 1;\n    int leftMax = 0, rightMax = 0;\n    int ans = 0;\n    while (left < right) {\n        if (height[left] < height[right]) {\n            if (height[left] >= leftMax) {\n                leftMax = height[left];\n            } else {\n                ans += leftMax - height[left];\n            }\n            left++;\n        } else {\n            if (height[right] >= rightMax) {\n                rightMax = height[right];\n            } else {\n                ans += rightMax - height[right];\n            }\n            right--;\n        }\n    }\n    return ans;\n}', 'hard', '[{"input":"[0,1,0,2,1,0,1,3,2,1,2,1]","output":"6"},{"input":"[4,2,0,3,2,5]","output":"9"}]', '{"timeLimit":1000,"memoryLimit":256,"stackLimit":256}', 1),

('LRU 缓存', '请你设计并实现一个满足 LRU (最近最少使用) 缓存 约束的数据结构。\n\n实现 LRUCache 类：\nLRUCache(int capacity) 以 正整数 作为容量 capacity 初始化 LRU 缓存\nint get(int key) 如果关键字 key 存在于缓存中，则返回关键字的值，否则返回 -1 。\nvoid put(int key, int value) 如果关键字 key 已经存在，则变更其数据值 value ；如果不存在，则向缓存中插入该组 key-value 。如果插入操作导致关键字数量超过 capacity ，则应该 逐出 最久未使用的关键字。', '["设计","哈希表","链表"]', 'class LRUCache {\n    class DLinkedNode {\n        int key;\n        int value;\n        DLinkedNode prev;\n        DLinkedNode next;\n        public DLinkedNode() {}\n        public DLinkedNode(int _key, int _value) {key = _key; value = _value;}\n    }\n\n    private Map<Integer, DLinkedNode> cache = new HashMap<>();\n    private int size;\n    private int capacity;\n    private DLinkedNode head, tail;\n\n    public LRUCache(int capacity) {\n        this.size = 0;\n        this.capacity = capacity;\n        head = new DLinkedNode();\n        tail = new DLinkedNode();\n        head.next = tail;\n        tail.prev = head;\n    }\n    \n    public int get(int key) {\n        DLinkedNode node = cache.get(key);\n        if (node == null) {\n            return -1;\n        }\n        moveToHead(node);\n        return node.value;\n    }\n    \n    public void put(int key, int value) {\n        DLinkedNode node = cache.get(key);\n        if (node == null) {\n            DLinkedNode newNode = new DLinkedNode(key, value);\n            cache.put(key, newNode);\n            addToHead(newNode);\n            ++size;\n            if (size > capacity) {\n                DLinkedNode tail = removeTail();\n                cache.remove(tail.key);\n                --size;\n            }\n        }\n        else {\n            node.value = value;\n            moveToHead(node);\n        }\n    }\n\n    private void addToHead(DLinkedNode node) {\n        node.prev = head;\n        node.next = head.next;\n        head.next.prev = node;\n        head.next = node;\n    }\n\n    private void removeNode(DLinkedNode node) {\n        node.prev.next = node.next;\n        node.next.prev = node.prev;\n    }\n\n    private void moveToHead(DLinkedNode node) {\n        removeNode(node);\n        addToHead(node);\n    }\n\n    private DLinkedNode removeTail() {\n        DLinkedNode res = tail.prev;\n        removeNode(res);\n        return res;\n    }\n}', 'medium', '[{"input":"[\"LRUCache\", \"put\", \"put\", \"get\", \"put\", \"get\", \"put\", \"get\", \"get\", \"get\"]","output":"[null, null, null, 1, null, -1, null, 3, 4, 4]"}]', '{"timeLimit":1000,"memoryLimit":256,"stackLimit":256}', 1),

('最长有效括号', '给你一个只包含 \'(\' 和 \')\' 的字符串，找出最长有效（格式正确且连续）括号子串的长度。', '["字符串","动态规划","栈"]', 'public int longestValidParentheses(String s) {\n    int maxans = 0;\n    Stack<Integer> stack = new Stack<>();\n    stack.push(-1);\n    for (int i = 0; i < s.length(); i++) {\n        if (s.charAt(i) == \'(\') {\n            stack.push(i);\n        } else {\n            stack.pop();\n            if (stack.empty()) {\n                stack.push(i);\n            } else {\n                maxans = Math.max(maxans, i - stack.peek());\n            }\n        }\n    }\n    return maxans;\n}', 'hard', '[{"input":"\"(()\"","output":"2"},{"input":"\")()())\"","output":"4"}]', '{"timeLimit":1000,"memoryLimit":256,"stackLimit":256}', 1);